use std::fs;
use std::path::{Path, PathBuf};

use super::adapter::{BuildAdapter, detect_build_adapter};

const TAKO_GEN_HEADER: &str = r#"/**
 * AUTO-GENERATED BY TAKO — DO NOT EDIT
 *
 * Regenerated by the Tako CLI on init, dev, deploy, `tako typegen`, and
 * secrets changes. Manual edits will be overwritten on the next run.
 */

import { createLogger, loadSecrets } from "tako.sh/runtime";

"#;

const JS_MODULE_EXTS: &[&str] = &[".ts", ".tsx", ".js", ".mjs", ".mts"];

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub struct JsTypegenResult {
    pub wrote_runtime_types: bool,
    pub wrote_scaffolds: bool,
}

/// Read the declared environment names from `tako.toml`'s `[envs.*]` tables.
///
/// "development" and "production" are always included as base environments
/// (so apps running under `tako dev` always typecheck). Any additional envs
/// declared in `tako.toml` are merged in, sorted, deduplicated.
fn read_env_names(project_dir: &Path) -> Vec<String> {
    let mut names: std::collections::BTreeSet<String> = ["development", "production"]
        .iter()
        .map(|s| s.to_string())
        .collect();

    for candidate in ["tako.toml"] {
        let path = project_dir.join(candidate);
        let Ok(content) = fs::read_to_string(&path) else {
            continue;
        };
        let Ok(parsed): Result<toml::Value, _> = toml::from_str(&content) else {
            continue;
        };
        if let Some(envs) = parsed.get("envs").and_then(|v| v.as_table()) {
            for name in envs.keys() {
                names.insert(name.clone());
            }
        }
        break;
    }

    names.into_iter().collect()
}

/// Read secret names from `.tako/secrets.json` for the "development" environment.
///
/// Falls back to all secret names across all environments if no development
/// environment exists. Returns an empty vec if the file doesn't exist or is
/// malformed.
fn read_secret_names(project_dir: &Path) -> Vec<String> {
    let secrets_path = project_dir.join(".tako").join("secrets.json");
    let Ok(content) = fs::read_to_string(&secrets_path) else {
        return Vec::new();
    };

    let Ok(parsed): Result<serde_json::Value, _> = serde_json::from_str(&content) else {
        return Vec::new();
    };

    let Some(envs) = parsed.as_object() else {
        return Vec::new();
    };

    if let Some(dev) = envs.get("development")
        && let Some(secrets) = dev.get("secrets").and_then(|s| s.as_object())
    {
        let mut names: Vec<String> = secrets.keys().cloned().collect();
        names.sort();
        return names;
    }

    let mut names_set = std::collections::BTreeSet::new();
    for env_value in envs.values() {
        if let Some(secrets) = env_value.get("secrets").and_then(|s| s.as_object()) {
            for name in secrets.keys() {
                names_set.insert(name.clone());
            }
        }
    }
    names_set.into_iter().collect()
}

fn build_secrets_block(names: &[String]) -> String {
    let mut out = String::new();
    out.push_str(
        "/**\n * Shape of the {@link secrets} export. One `readonly string` field per key in\n * `.tako/secrets.json`. Bulk serialization returns `\"[REDACTED]\"` so logging\n * the whole object by accident can't leak values.\n *\n * @example\n * ```ts\n * import { secrets } from \"../tako.gen\";\n *\n * const dbUrl = secrets.DATABASE_URL;     // typed string\n * console.log(secrets);                   // \"[REDACTED]\"\n * ```\n */\n",
    );
    if names.is_empty() {
        out.push_str("// eslint-disable-next-line @typescript-eslint/no-empty-object-type\n");
        out.push_str("export interface Secrets {\n");
    } else {
        out.push_str("export interface Secrets {\n");
        for name in names {
            out.push_str(&format!(
                "  /** Secret `{name}` — injected by Tako at runtime. */\n"
            ));
            out.push_str(&format!("  readonly {name}: string;\n"));
        }
        out.push_str(
            "  /** `String(secrets)` returns `\"[REDACTED]\"` to prevent accidental leaks. */\n",
        );
        out.push_str("  toString(): \"[REDACTED]\";\n");
        out.push_str(
            "  /** `JSON.stringify(secrets)` returns `\"[REDACTED]\"` to prevent accidental leaks. */\n",
        );
        out.push_str("  toJSON(): \"[REDACTED]\";\n");
    }
    out.push_str("}\n\n");
    out
}

fn build_runtime_block() -> String {
    r#"/**
 * Augment `process.env` / `import.meta.env` with the vars Tako guarantees
 * are set on every spawned instance (both `tako deploy` and `tako dev`).
 * `process.env.ENV` is narrowed to the project's {@link Env} union; the
 * rest are always-defined strings.
 *
 * @example
 * ```ts
 * // With the augmentation, direct `process.env` reads are typed:
 * if (process.env.ENV === "production") startMetricsReporter();
 * const PORT = Number(process.env.PORT); // number, no `!` needed
 * ```
 */
declare global {
  namespace NodeJS {
    interface ProcessEnv {
      /** Current environment. Narrowed to `[envs.*]` declared in `tako.toml`. */
      readonly ENV: Env;
      /** Port Tako assigned to this app instance. */
      readonly PORT: string;
      /** Host/address Tako bound this app instance to. */
      readonly HOST: string;
      /** Build identifier injected by Tako at deploy time. `"dev"` under `tako dev`. */
      readonly TAKO_BUILD: string;
      /** Persistent app-owned data directory — writes survive restarts and deploys. */
      readonly TAKO_DATA_DIR: string;
    }
  }
  interface ImportMetaEnv {
    /** Current environment. Narrowed to `[envs.*]` declared in `tako.toml`. */
    readonly ENV: Env;
    /** Port Tako assigned to this app instance. */
    readonly PORT: string;
    /** Host/address Tako bound this app instance to. */
    readonly HOST: string;
    /** Build identifier injected by Tako at deploy time. `"dev"` under `tako dev`. */
    readonly TAKO_BUILD: string;
    /** Persistent app-owned data directory — writes survive restarts and deploys. */
    readonly TAKO_DATA_DIR: string;
  }
}

/**
 * Tako populates `process.env` on the server — these accessors guard the
 * reads so importing `tako.gen.ts` from an isomorphic file (e.g. a
 * TanStack Start route or Next.js server component that also renders on
 * the client) does not throw `ReferenceError: process is not defined`.
 * Consumers that only read these in server-only code keep the same
 * types; client-side reads fall through to empty values.
 */
const __takoEnv: NodeJS.ProcessEnv =
  typeof process !== "undefined" && process.env
    ? process.env
    : ({} as NodeJS.ProcessEnv);

/**
 * Current environment. TypeScript narrows this against the project's
 * {@link Env} union, so `env === "staging"` is a compile error unless
 * `[envs.staging]` is declared in `tako.toml`.
 *
 * @example
 * ```ts
 * import { env } from "../tako.gen";
 *
 * switch (env) {
 *   case "production": return getProductionClient();
 *   case "development": return getMockClient();
 * }
 * ```
 */
export const env = __takoEnv.ENV;

/**
 * `true` when the app is running under `tako dev`.
 *
 * @example
 * ```ts
 * import { isDev } from "../tako.gen";
 *
 * const log = isDev ? console.log : () => {};
 * ```
 */
export const isDev = env === "development";

/**
 * `true` when the app is running under `tako deploy` in a production env.
 *
 * @example
 * ```ts
 * import { isProd, logger } from "../tako.gen";
 *
 * if (isProd) logger.info("request", { userId, path });
 * ```
 */
export const isProd = env === "production";

/**
 * Port Tako assigned to this app instance. Pass straight to your server.
 *
 * @example
 * ```ts
 * import { port, host } from "../tako.gen";
 *
 * Bun.serve({ port, hostname: host, fetch: handleRequest });
 * ```
 */
export const port = /* @__PURE__ */ Number(__takoEnv.PORT);

/** Host/address Tako bound this app instance to. */
export const host = __takoEnv.HOST;

/**
 * Build identifier. Production deploys use a content hash; `tako dev` uses
 * the literal string `"dev"`. Handy for cache keys and error reports.
 *
 * @example
 * ```ts
 * import { build } from "../tako.gen";
 *
 * Sentry.init({ release: build });
 * ```
 */
export const build = __takoEnv.TAKO_BUILD;

/**
 * Persistent app-owned data directory. Writes survive restarts and deploys —
 * ideal for SQLite files, uploaded assets, and long-lived caches.
 *
 * @example
 * ```ts
 * import { Database } from "bun:sqlite";
 * import { join } from "node:path";
 * import { dataDir } from "../tako.gen";
 *
 * const db = new Database(join(dataDir, "app.db"));
 * ```
 */
export const dataDir = __takoEnv.TAKO_DATA_DIR;

/** Directory the app is running from (`process.cwd()`). */
export const appDir = /* @__PURE__ */ (() =>
  typeof process !== "undefined" && typeof process.cwd === "function"
    ? process.cwd()
    : "")();

/**
 * Structured JSON logger bound to `source: "app"`. Emits one line per call
 * to stdout in a shape `tako dev` and production log pipelines understand.
 *
 * @example
 * ```ts
 * import { logger } from "../tako.gen";
 *
 * logger.info("user signed in", { userId, ip });
 * logger.error("payment failed", { orderId, err: String(err) });
 * ```
 */
export const logger = /* @__PURE__ */ createLogger("app");

/**
 * Tako-managed secrets, typed by the {@link Secrets} interface. Individual
 * lookups return the string value; bulk serialization is redacted.
 *
 * @example
 * ```ts
 * import { secrets } from "../tako.gen";
 *
 * const db = postgres(secrets.DATABASE_URL);
 *
 * console.log(secrets);            // "[REDACTED]"
 * JSON.stringify(secrets);         // "\"[REDACTED]\""
 * secrets.DATABASE_URL = "oops";   // compile error — readonly
 * ```
 */
export const secrets = /* @__PURE__ */ loadSecrets<Secrets>();
"#
    .to_string()
}

fn build_env_block(env_names: &[String]) -> String {
    let mut out = String::from(
        "/**\n * Environments declared in `tako.toml` (plus `development` and `production`).\n * Use this anywhere you take an env name as input — TypeScript will reject\n * values that aren't in the union.\n *\n * @example\n * ```ts\n * import type { Env } from \"../tako.gen\";\n *\n * function featureFlag(flag: string, envs: readonly Env[]): boolean {\n *   return envs.includes(process.env.ENV);\n * }\n * ```\n */\n",
    );
    out.push_str("export type Env = ");
    let mut first = true;
    for name in env_names {
        if !first {
            out.push_str(" | ");
        }
        out.push('"');
        out.push_str(name);
        out.push('"');
        first = false;
    }
    out.push_str(";\n\n");
    out
}

/// Build the full `tako.gen.ts` content.
fn build_gen(secret_names: &[String], env_names: &[String]) -> String {
    let mut out = String::from(TAKO_GEN_HEADER);
    out.push_str(&build_env_block(env_names));
    out.push_str(&build_secrets_block(secret_names));
    out.push_str(&build_runtime_block());
    out
}

/// Write `tako.gen.ts` to the project. Prefers an existing location if one
/// is found (honors tsconfig `include` patterns like `src/**/*`); otherwise
/// drops it at the project root.
pub fn write_types(project_dir: &Path) -> std::io::Result<bool> {
    write_types_for_adapter(project_dir, detect_build_adapter(project_dir))
}

/// Like [`write_types`] but with an explicit adapter (currently unused —
/// the generated file is runtime-agnostic, but we keep the parameter for
/// symmetry with `write_types_go` and forward compatibility).
pub fn write_types_for_adapter(
    project_dir: &Path,
    _adapter: BuildAdapter,
) -> std::io::Result<bool> {
    let secret_names = read_secret_names(project_dir);
    let env_names = read_env_names(project_dir);
    let content = build_gen(&secret_names, &env_names);
    let path = resolve_gen_path(project_dir);
    if let Some(parent) = path.parent()
        && !parent.as_os_str().is_empty()
    {
        fs::create_dir_all(parent)?;
    }
    if let Ok(existing) = fs::read_to_string(&path)
        && existing == content
    {
        return Ok(false);
    }
    fs::write(&path, content)?;

    // Best-effort removal of the legacy `tako.d.ts` file (and any empty dir it
    // leaves behind) so regenerated projects don't carry around ambient types
    // that no longer apply.
    for dir in ["", "src", "app"] {
        let legacy = if dir.is_empty() {
            project_dir.join("tako.d.ts")
        } else {
            project_dir.join(dir).join("tako.d.ts")
        };
        if legacy.is_file() {
            let _ = fs::remove_file(&legacy);
        }
    }

    Ok(true)
}

pub fn write_typegen_support_files(project_dir: &Path) -> std::io::Result<JsTypegenResult> {
    write_typegen_support_files_for_adapter(project_dir, detect_build_adapter(project_dir))
}

pub fn write_typegen_support_files_for_adapter(
    project_dir: &Path,
    adapter: BuildAdapter,
) -> std::io::Result<JsTypegenResult> {
    let wrote_runtime_types = write_types_for_adapter(project_dir, adapter)?;
    let wrote_scaffolds = ensure_js_definition_scaffolds(project_dir)?;
    Ok(JsTypegenResult {
        wrote_runtime_types,
        wrote_scaffolds,
    })
}

/// Resolve where `tako.gen.ts` belongs for this project.
///
/// Prefers any existing `tako.gen.ts` location; falls back to `src/` then
/// `app/`, finally the project root.
fn resolve_gen_path(project_dir: &Path) -> PathBuf {
    const CANDIDATE_DIRS: &[&str] = &["src", "app"];

    let root = project_dir.join("tako.gen.ts");
    if root.is_file() {
        return root;
    }
    for dir in CANDIDATE_DIRS {
        let candidate = project_dir.join(dir).join("tako.gen.ts");
        if candidate.is_file() {
            return candidate;
        }
    }
    for dir in CANDIDATE_DIRS {
        let candidate_dir = project_dir.join(dir);
        if candidate_dir.is_dir() {
            return candidate_dir.join("tako.gen.ts");
        }
    }
    root
}

#[derive(Clone, Copy)]
enum StubKind {
    Channel,
    Workflow,
}

impl StubKind {
    fn dir_name(self) -> &'static str {
        match self {
            Self::Channel => "channels",
            Self::Workflow => "workflows",
        }
    }

    fn helper_name(self) -> &'static str {
        match self {
            Self::Channel => "defineChannel",
            Self::Workflow => "defineWorkflow",
        }
    }

    fn default_export_line(self, stem: &str) -> String {
        match self {
            Self::Channel => "export default defineChannel({}).$messageTypes<{}>();".to_string(),
            Self::Workflow => {
                format!(
                    "export default defineWorkflow(\"{stem}\", {{ handler: async () => {{}} }});"
                )
            }
        }
    }
}

fn ensure_js_definition_scaffolds(project_dir: &Path) -> std::io::Result<bool> {
    let mut wrote_any = false;
    for kind in [StubKind::Channel, StubKind::Workflow] {
        wrote_any |= ensure_dir_scaffolds(&project_dir.join(kind.dir_name()), kind)?;
    }
    Ok(wrote_any)
}

fn ensure_dir_scaffolds(dir: &Path, kind: StubKind) -> std::io::Result<bool> {
    if !dir.is_dir() {
        return Ok(false);
    }

    let mut module_files = Vec::new();
    for entry in fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        let Ok(file_type) = entry.file_type() else {
            continue;
        };
        if !file_type.is_file() {
            continue;
        }
        let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
            continue;
        };
        if name.starts_with('.') || name.starts_with('_') {
            continue;
        }
        let Some(ext) = path.extension().and_then(|ext| ext.to_str()) else {
            continue;
        };
        let dot_ext = format!(".{ext}");
        if JS_MODULE_EXTS.contains(&dot_ext.as_str()) {
            module_files.push(path);
        }
    }
    module_files.sort();

    let mut wrote_any = false;
    if module_files.is_empty() {
        let stub_path = dir.join("demo.ts");
        let content = render_scaffold(kind, "demo", "");
        fs::write(stub_path, content)?;
        return Ok(true);
    }

    for path in module_files {
        let existing = fs::read_to_string(&path)?;
        let Some(stem) = path.file_stem().and_then(|stem| stem.to_str()) else {
            continue;
        };
        let Some(updated) = maybe_scaffold_source(kind, stem, &existing) else {
            continue;
        };
        if updated != existing {
            fs::write(&path, updated)?;
            wrote_any = true;
        }
    }

    Ok(wrote_any)
}

fn maybe_scaffold_source(kind: StubKind, stem: &str, existing: &str) -> Option<String> {
    if existing.contains("export default") {
        return None;
    }
    Some(render_scaffold(kind, stem, existing))
}

fn render_scaffold(kind: StubKind, stem: &str, existing: &str) -> String {
    let mut out = String::new();
    if !existing.contains(kind.helper_name()) {
        out.push_str(&format!(
            "import {{ {} }} from \"tako.sh\";\n\n",
            kind.helper_name()
        ));
    }
    if existing.trim().is_empty() {
        out.push_str(&kind.default_export_line(stem));
        out.push('\n');
        return out;
    }

    out.push_str(existing);
    if !existing.ends_with('\n') {
        out.push('\n');
    }
    out.push('\n');
    out.push_str(&kind.default_export_line(stem));
    out.push('\n');
    out
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn write_types_creates_tako_gen_with_no_secrets() {
        let dir = TempDir::new().unwrap();
        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.gen.ts")).unwrap();
        assert!(content.contains("AUTO-GENERATED BY TAKO"));
        assert!(content.contains("export interface Secrets"));
        assert!(content.contains("export const env"));
        assert!(content.contains("export const secrets"));
    }

    #[test]
    fn write_types_imports_from_browser_safe_runtime_entry() {
        // The generated file gets bundled into client chunks by TanStack
        // Start / Next.js / any isomorphic framework. Importing from
        // `tako.sh/internal` would drag `node:fs` / `node:net` statics
        // into the browser graph; `tako.sh/runtime` is the server-safe
        // subset (logger + secrets only).
        let dir = TempDir::new().unwrap();
        write_types(dir.path()).unwrap();
        let content = fs::read_to_string(dir.path().join("tako.gen.ts")).unwrap();
        assert!(content.contains(r#"from "tako.sh/runtime""#));
        assert!(!content.contains(r#"from "tako.sh/internal""#));
    }

    #[test]
    fn write_types_guards_process_env_reads_for_browser_bundlers() {
        // Isomorphic files (e.g. a TanStack Start route) can import from
        // `tako.gen.ts` and be bundled into the client. A bare
        // `process.env.X` at module scope throws `ReferenceError: process
        // is not defined` in the browser; guard it.
        let dir = TempDir::new().unwrap();
        write_types(dir.path()).unwrap();
        let content = fs::read_to_string(dir.path().join("tako.gen.ts")).unwrap();
        assert!(content.contains(r#"typeof process !== "undefined""#));
        // The top-level exports must route through the guarded accessor.
        assert!(!content.contains("= process.env.ENV"));
        assert!(!content.contains("= process.env.PORT"));
        assert!(!content.contains("= process.env.HOST"));
        assert!(!content.contains("= process.env.TAKO_BUILD"));
        assert!(!content.contains("= process.env.TAKO_DATA_DIR"));
    }

    #[test]
    fn write_types_is_idempotent() {
        let dir = TempDir::new().unwrap();
        let written_first = write_types(dir.path()).unwrap();
        assert!(written_first);
        let written_second = write_types(dir.path()).unwrap();
        assert!(!written_second);
    }

    #[test]
    fn write_types_with_secrets_generates_typed_interface() {
        let dir = TempDir::new().unwrap();
        let secrets_dir = dir.path().join(".tako");
        fs::create_dir_all(&secrets_dir).unwrap();
        fs::write(
            secrets_dir.join("secrets.json"),
            r#"{"development":{"secrets":{"API_KEY":"x","DATABASE_URL":"y"}}}"#,
        )
        .unwrap();

        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.gen.ts")).unwrap();
        assert!(content.contains("readonly API_KEY: string;"));
        assert!(content.contains("readonly DATABASE_URL: string;"));
        assert!(content.contains("toString(): \"[REDACTED]\";"));
    }

    #[test]
    fn write_types_deletes_legacy_tako_dts() {
        let dir = TempDir::new().unwrap();
        fs::write(dir.path().join("tako.d.ts"), "// legacy").unwrap();

        write_types(dir.path()).unwrap();

        assert!(!dir.path().join("tako.d.ts").exists());
        assert!(dir.path().join("tako.gen.ts").exists());
    }

    #[test]
    fn typegen_creates_demo_channel_and_workflow_in_empty_dirs() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("channels")).unwrap();
        fs::create_dir_all(dir.path().join("workflows")).unwrap();

        let result = write_typegen_support_files(dir.path()).unwrap();

        assert!(result.wrote_scaffolds);
        let channel = fs::read_to_string(dir.path().join("channels").join("demo.ts")).unwrap();
        assert!(channel.contains(r#"import { defineChannel } from "tako.sh";"#));
        assert!(channel.contains(r#"export default defineChannel({}).$messageTypes<{}>();"#));

        let workflow = fs::read_to_string(dir.path().join("workflows").join("demo.ts")).unwrap();
        assert!(workflow.contains(r#"import { defineWorkflow } from "tako.sh";"#));
        assert!(
            workflow
                .contains(r#"export default defineWorkflow("demo", { handler: async () => {} });"#)
        );
    }

    #[test]
    fn typegen_populates_empty_channel_and_workflow_files() {
        let dir = TempDir::new().unwrap();
        let channels_dir = dir.path().join("channels");
        let workflows_dir = dir.path().join("workflows");
        fs::create_dir_all(&channels_dir).unwrap();
        fs::create_dir_all(&workflows_dir).unwrap();
        fs::write(channels_dir.join("mission-log.ts"), "  \n").unwrap();
        fs::write(workflows_dir.join("send-email.ts"), "\n").unwrap();

        let result = write_typegen_support_files(dir.path()).unwrap();

        assert!(result.wrote_scaffolds);
        let channel = fs::read_to_string(channels_dir.join("mission-log.ts")).unwrap();
        assert!(channel.contains(r#"export default defineChannel({}).$messageTypes<{}>();"#));
        let workflow = fs::read_to_string(workflows_dir.join("send-email.ts")).unwrap();
        assert!(workflow.contains(
            r#"export default defineWorkflow("send-email", { handler: async () => {} });"#
        ));
    }

    #[test]
    fn typegen_adds_missing_default_exports_without_overwriting_existing_content() {
        let dir = TempDir::new().unwrap();
        let channels_dir = dir.path().join("channels");
        let workflows_dir = dir.path().join("workflows");
        fs::create_dir_all(&channels_dir).unwrap();
        fs::create_dir_all(&workflows_dir).unwrap();
        fs::write(
            channels_dir.join("mission-log.ts"),
            "const pattern = \"mission-log/:base\";\n",
        )
        .unwrap();
        fs::write(
            workflows_dir.join("send-email.ts"),
            "const send = async () => {};\n",
        )
        .unwrap();

        let result = write_typegen_support_files(dir.path()).unwrap();

        assert!(result.wrote_scaffolds);
        let channel = fs::read_to_string(channels_dir.join("mission-log.ts")).unwrap();
        assert!(channel.starts_with("import { defineChannel } from \"tako.sh\";\n"));
        assert!(channel.contains("const pattern = \"mission-log/:base\";"));
        assert!(channel.contains(r#"export default defineChannel({}).$messageTypes<{}>();"#));

        let workflow = fs::read_to_string(workflows_dir.join("send-email.ts")).unwrap();
        assert!(workflow.starts_with("import { defineWorkflow } from \"tako.sh\";\n"));
        assert!(workflow.contains("const send = async () => {};"));
        assert!(workflow.contains(
            r#"export default defineWorkflow("send-email", { handler: async () => {} });"#
        ));
    }

    #[test]
    fn typegen_leaves_existing_default_exports_untouched() {
        let dir = TempDir::new().unwrap();
        let channels_dir = dir.path().join("channels");
        let workflows_dir = dir.path().join("workflows");
        fs::create_dir_all(&channels_dir).unwrap();
        fs::create_dir_all(&workflows_dir).unwrap();
        let channel_src = "export default somethingElse;\n";
        let workflow_src = "export default async function run() {}\n";
        fs::write(channels_dir.join("demo.ts"), channel_src).unwrap();
        fs::write(workflows_dir.join("demo.ts"), workflow_src).unwrap();

        let result = write_typegen_support_files(dir.path()).unwrap();

        assert!(!result.wrote_scaffolds);
        assert_eq!(
            fs::read_to_string(channels_dir.join("demo.ts")).unwrap(),
            channel_src
        );
        assert_eq!(
            fs::read_to_string(workflows_dir.join("demo.ts")).unwrap(),
            workflow_src
        );
    }
}
